  object QueryValidator {
    private val blockedPatterns = Seq(
      "(?i)\\bINSERT\\b".r,
      "(?i)\\bUPDATE\\b".r,
      "(?i)\\bDELETE\\b".r,
      "(?i)\\bMERGE\\b".r,
      "(?i)\\bDROP\\b".r,
      "(?i)\\bTRUNCATE\\b".r,
      "(?i)\\bALTER\\b".r,
      "(?i)\\bCREATE\\b".r,
      "(?i)\\bREPLACE\\b".r,
      "(?i)\\bCACHE\\b".r,
      "(?i)\\bUNCACHE\\b".r,
      "(?i)\\bLOAD\\b".r,
      "(?i)\\bEXPORT\\b".r,
      "(?i)\\bIMPORT\\b".r,
      "(?i);".r
    )

    def validate(query: String): Either[String, String] = {
      val normalized = Option(query).map(_.trim).getOrElse("")
      if (normalized.isEmpty) Left("Query must not be empty")
      else if (!normalized.toUpperCase.startsWith("SELECT") && !normalized.toUpperCase.startsWith("WITH")) {
        Left("Only read-only SELECT/WITH queries are allowed")
      } else {
        val matched = blockedPatterns.exists(_.findFirstIn(normalized).isDefined)
        if (matched) Left("Query contains forbidden statements or delimiters")
        else Right(normalized)
      }
    }
  }

  object ResultSerializer {
    def toApiResponse(requestId: String, df: DataFrame, limit: Int): ApiResponse = {
      val limited = df.limit(limit)
      val columns = limited.columns.toSeq
      val rows = limited.collect().toSeq.map { row =>
        columns.zipWithIndex.map { case (name, idx) =>
          name -> Option(row.get(idx)).map(_.toString).getOrElse(null)
        }.toMap
      }
      ApiResponse(
        requestId = requestId,
        status = "OK",
        message = s"Query executed successfully. Returned up to $limit rows.",
        columns = columns,
        rows = rows
      )
    }

    def error(requestId: String, message: String): ApiResponse =
      ApiResponse(
        requestId = requestId,
        status = "ERROR",
        message = message,
        columns = Seq.empty,
        rows = Seq.empty
      )
  }

  final class AnalyticsQueryService(spark: SparkSession, maxRows: Int) {

    def execute(request: ApiRequest): ApiResponse = {
      QueryValidator.validate(request.sql) match {
        case Left(validationError) =>
